concept_explanation.consumer_test:
**Pact Consumer Test (Flipkart side):**

```java
@ExtendWith(PactConsumerTestExt.class)
@PactTestFor(providerName="razorpay-payment-api")
class FlipkartPaymentConsumerTest {

    @Pact(consumer="flipkart-checkout", provider="razorpay-payment-api")
    RequestResponsePact createPaymentPact(PactDslWithProvider builder) {
        return builder
            .given("merchant MRC-001 exists")  // provider state
            .uponReceiving("create payment request")
                .method("POST")
                .path("/api/payments")
                .body(new PactDslJsonBody()
                    .stringType("merchantId", "MRC-001")
                    .numberType("amountPaise", 500000L))
            .willRespondWith()
                .status(201)
                .body(new PactDslJsonBody()
                    .stringType("paymentId")    // must be a string
                    .stringMatcher("status", "SUCCESS|PENDING", "SUCCESS")
                    .numberType("amountPaise")) // must be a number
            .toPact();
    }

    @Test
    @PactTestFor(pactMethod="createPaymentPact")
    void consumer_callsPaymentApi_correctly(MockServer mockServer) {
        // Pact starts a mock server matching the contract:
        PaymentClient client = new PaymentClient(mockServer.getUrl());
        PaymentResponse response = client.createPayment("MRC-001", 500000L);

        assertNotNull(response.paymentId()); // must be present
        assertEquals("SUCCESS", response.status());
    }
}
```

